# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import logging
import json
import os
from azure.functions import TimerRequest
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import DefaultAzureCredential

def main(mytimer: TimerRequest):
    # Initialize clients using managed identity
    credential = DefaultAzureCredential()
    
    # Blob Storage client
    blob_service_client = BlobServiceClient(
        account_url=os.environ["STORAGE_ACCOUNT_URL"],
        credential=credential
    )
    
    # Cosmos DB client
    cosmos_client = CosmosClient(
        account_url=os.environ["COSMOS_ACCOUNT_URL"],
        credential=credential
    )
    
    # Event Grid client
    event_grid_client = EventGridPublisherClient(
        endpoint=os.environ["EVENT_GRID_ENDPOINT"],
        credential=credential
    )
    
    # Process blobs
    container_client = blob_service_client.get_container_client("input-container")
    blob_list = container_client.list_blobs()
    
    for blob in blob_list:
        try:
            # Read blob content
            blob_data = container_client.get_blob_client(blob).download_blob().readall()
            
            # Process data (example: convert to uppercase)
            processed_data = blob_data.decode('utf-8').upper()
            
            # Write to Cosmos DB
            database = cosmos_client.get_database_client("mydatabase")
            container = database.get_container_client("mycontainer")
            
            container.create_item({
                "id": blob.name,
                "content": processed_data,
                "processed_at": "2023-01-01T00:00:00Z"
            })
            
            # Send notification via Event Grid
            event = EventGridEvent(
                event_type="BlobProcessed",
                subject=f"blob/{blob.name}",
                data={"blob_name": blob.name, "status": "processed"},
                data_version="1.0"
            )
            
            event_grid_client.send([event])
            
            logging.info(f"Processed blob: {blob.name}")
            
        except Exception as e:
            logging.error(f"Error processing blob {blob.name}: {str(e)}")